extension ViewController: WKNavigationDelegate {
    func webView(_ webView: WKWebView, runJavaScriptAlertPanelWithMessage message: String, initiatedByFrame frame: WKFrameInfo, completionHandler: (@escaping () -> Void)) {
        showAlert(message: message)
        completionHandler()
    }

    func webView(_ webView: WKWebView, runJavaScriptConfirmPanelWithMessage message: String, initiatedByFrame frame: WKFrameInfo, completionHandler: (@escaping (Bool) -> Void)) {
        let alertController = UIAlertController(title: "Confirmation", message: message, preferredStyle: .alert)
        alertController.addAction(UIAlertAction(title: "Yes", style: .default) { (_) in
            completionHandler(true)
        })
        alertController.addAction(UIAlertAction(title: "No", style: .cancel) { (_) in
            completionHandler(false)
        })
        present(alertController, animated: true, completion: nil)
    }

    func webView(_ webView: WKWebView, runJavaScriptTextInputPanelWithPrompt prompt: String, defaultText: String?, initiatedByFrame frame: WKFrameInfo, completionHandler: (@escaping (String?) -> Void)) {
        let alertController = UIAlertController(title: "Input", message: prompt, preferredStyle: .alert)
        alertController.addTextField { textField in
            textField.text = defaultText
        }
        let action = UIAlertAction(title: "OK", style: .default) { (_) in
            if let textField = alertController.textFields?.first, let text = textField.text {
                completionHandler(text)
            } else {
                completionHandler(nil)
            }
        }
        alertController.addAction(action)
        present(alertController, animated: true, completion: nil)
    }
